mapper.select:
SELECT md.id, md.major_id, m.major_name, md.direction_name, md.direction_code, md.level, md.years, md.is_segmented, md.phase1_level, md.phase1_years, md.phase2_level, md.phase2_years, md.remarks, md.created_at, md.updated_at FROM major_directions md LEFT JOIN majors m ON md.major_id = m.id WHERE md.deleted = 0
AND md.major_id = #{params.majorId}
AND md.direction_name LIKE CONCAT('%', #{params.directionName}, '%')
AND md.level = #{params.level}
AND md.is_segmented = #{params.isSegmented}
ORDER BY m.major_name, md.created_at DESC
